#!/usr/bin/env python3
"""
Comment hygiene checker — detects ephemeral-artifact pointers in code comment lines.

Usage: check-comment-hygiene.sh <file>

Exit codes:
  0 — file is clean (no violations found)
  1 — violations found (reported to stdout as FILEPATH:LINE: excerpt)
  2 — file skipped (binary, unknown extension, or in excluded dir)

Escape: add "hygiene-ok" anywhere on a comment line to suppress it.

See: .opencode/skills/sk-code/references/universal/code_style_guide.md §4
"""
import sys
import os
import re

def main():
    if len(sys.argv) < 2:
        print("Usage: check-comment-hygiene.sh <file>", file=sys.stderr)
        sys.exit(2)

    filepath = sys.argv[1]

    # --- Excluded directories and file patterns ---
    abs_path = os.path.abspath(filepath)
    excluded_dirs = ["/dist/", "/node_modules/", "/.git/"]
    for excl in excluded_dirs:
        if excl in abs_path:
            sys.exit(2)

    basename = os.path.basename(filepath)
    if basename.endswith(".vitest.js"):
        sys.exit(2)

    # --- Language detection from extension ---
    _, ext = os.path.splitext(basename)
    ext = ext.lower()

    if ext in (".ts", ".tsx", ".js", ".mjs", ".cjs"):
        lang = "js"
    elif ext == ".py":
        lang = "py"
    elif ext in (".sh", ".bash"):
        lang = "sh"
    elif ext == ".jsonc":
        lang = "jsonc"
    else:
        # Unknown extension — skip silently
        sys.exit(2)

    # --- Read file ---
    try:
        with open(filepath, "r", encoding="utf-8", errors="replace") as f:
            lines = f.readlines()
    except (OSError, IOError) as e:
        print(f"WARNING: cannot read {filepath}: {e}", file=sys.stderr)
        sys.exit(0)

    # --- Comment detection ---
    def find_unquoted_js_line_comment(line: str) -> int:
        in_string = False
        quote = ""
        escaping = False

        index = 0
        while index < len(line):
            char = line[index]
            next_char = line[index + 1] if index + 1 < len(line) else ""

            if in_string:
                if escaping:
                    escaping = False
                elif char == "\\":
                    escaping = True
                elif char == quote:
                    in_string = False
                index += 1
                continue

            if char in ("'", '"', "`"):
                in_string = True
                quote = char
                index += 1
                continue

            if char == "/" and next_char == "/":
                return index

            index += 1

        return -1

    def find_unquoted_hash_comment(line: str) -> int:
        in_string = False
        quote = ""
        escaping = False

        for index, char in enumerate(line):
            if in_string:
                if escaping:
                    escaping = False
                elif char == "\\" and quote != "'":
                    escaping = True
                elif char == quote:
                    in_string = False
                continue

            if char in ("'", '"'):
                in_string = True
                quote = char
                continue

            if char == "#" and (index == 0 or line[index - 1].isspace()):
                return index

        return -1

